import{_ as a,c as m,o as e,b as t}from"./app.81e64653.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 21-22","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 21-22","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-29T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/21-22/index.md"}',r={},p=t('<div class="stanza"><a href="#s3.21" id="s3.21" class="num">3.21</a><div class="sans"><p>\u0905\u0924\u094D\u0930\u094B\u092A\u093E\u092F\u092E\u093E\u0939\u2014</p><blockquote><p><strong>\u092E\u0917\u094D\u0928\u0903 \u0938\u094D\u0935\u091A\u093F\u0924\u094D\u0924\u0947\u0928 \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0965\u0968\u0967\u0965</strong></p></blockquote><blockquote><p>\u092A\u094D\u0930\u093E\u0923\u093E\u0926\u093F\u0938\u094D\u0925\u0942\u0932\u092D\u093E\u0935\u0902 \u0924\u0941 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092E\u0925\u093E\u0928\u094D\u0924\u0930\u092E\u094D\u0964<br> \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E\u0924\u0940\u0924\u0902 \u0924\u0941 \u092A\u0930\u092E\u0902 \u0938\u094D\u092A\u0928\u094D\u0926\u0928\u0902 \u0932\u092D\u094D\u092F\u0924\u0947 \u092F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u092A\u0915\u094D\u0930\u092E\u094D\u092F</p><blockquote><p>... \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0924\u0924\u094D\u0938\u094D\u0935\u091A\u0947\u0924\u0938\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F \u0936\u094D\u0930\u0940\u092E\u0943\u0924\u094D\u092F\u0941\u091C\u093F\u0926\u094D\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0928\u093F\u0930\u0942\u092A\u093F\u0924\u0928\u0940\u0924\u094D\u092F\u093E \u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u0927\u094D\u092F\u093E\u0928\u0927\u093E\u0930\u0923\u093E\u0926\u093F\u0938\u094D\u0925\u0942\u0932\u094B\u092A\u093E\u092F\u093E\u0928\u094D\u092A\u0930\u093F\u0924\u094D\u092F\u091C\u094D\u092F \u0938\u094D\u0935\u091A\u093F\u0924\u094D\u0924\u0947\u0928\u093E\u0935\u093F\u0915\u0932\u094D\u092A\u0915\u0930\u0942\u092A\u0947\u0923\u093E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u093E\u0928\u094D\u0924\u0930\u0935\u093F\u092E\u0930\u094D\u0936\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u093E\u0924\u094D\u092E\u0928\u093E \u0938\u0902\u0935\u0947\u0926\u0928\u0947\u0928 \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0924\u094D\u0938\u092E\u093E\u0935\u093F\u0936\u0947\u0924\u094D\u0964 \u0915\u0940\u0926\u0943\u0915\u094D\u0938\u0928\u094D \u092E\u0917\u094D\u0928\u0903 \u0936\u0930\u0940\u0930\u092A\u094D\u0930\u093E\u0923\u093E\u0926\u093F\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u0902 \u0924\u0924\u094D\u0930\u0948\u0935 \u091A\u093F\u091A\u094D\u091A\u092E\u0924\u094D\u0915\u093E\u0930\u0930\u0938\u0947 \u092E\u091C\u094D\u091C\u0928\u0947\u0928 \u092A\u094D\u0930\u0936\u092E\u092F\u0928\u094D\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u092E\u094D \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u0935\u094D\u092F\u093E\u092A\u093E\u0930\u0902 \u092E\u093E\u0928\u0938\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u092C\u094B\u0927\u0930\u0942\u092A\u0947\u0923 \u092F\u094B\u091C\u092F\u0947\u0924\u094D\u0964<br> \u0924\u0926\u093E \u0936\u093F\u0935\u0924\u094D\u0935\u092E\u093E\u092F\u093E\u0924\u093F \u092A\u0936\u0941\u0930\u094D\u092E\u0941\u0915\u094D\u0924\u094B \u092D\u0935\u093E\u0930\u094D\u0923\u0935\u093E\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u091F\u094D\u091F\u093E\u0930\u0915\u0947\u093D\u092A\u093F</p><blockquote><p>\u092E\u093E\u0928\u0938\u0902 \u091A\u0947\u0924\u0928\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u093E\u0924\u094D\u092E\u093E \u091A\u0947\u0924\u093F \u091A\u0924\u0941\u0937\u094D\u091F\u092F\u092E\u094D\u0964<br> \u092F\u0926\u093E \u092A\u094D\u0930\u093F\u092F\u0947 \u092A\u0930\u093F\u0915\u094D\u0937\u0940\u0923\u0902 \u0924\u0926\u093E \u0924\u0926\u094D\u092D\u0948\u0930\u0935\u0902 \u0935\u092A\u0941\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u090F\u0924\u0926\u0947\u0935 \u091C\u094D\u091E\u093E\u0928\u0917\u0930\u094D\u092D\u0947 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0947</p><blockquote><p>\u0935\u093F\u0939\u093E\u092F \u0938\u0915\u0932\u093E\u0903 \u0915\u094D\u0930\u093F\u092F\u093E \u091C\u0928\u0928\u093F \u092E\u093E\u0928\u0938\u0940\u0903 \u0938\u0930\u094D\u0935\u0924\u094B \u0935\u093F\u092E\u0941\u0915\u094D\u0924\u0915\u0930\u0923\u0915\u094D\u0930\u093F\u092F\u093E\u0928\u0941\u0938\u0943\u0924\u093F\u092A\u093E\u0930\u0924\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u094B\u091C\u094D\u091C\u094D\u0935\u0932\u092E\u094D\u0964<br> \u0938\u094D\u0925\u093F\u0924\u0948\u0938\u094D\u0924\u094D\u0935\u0926\u0928\u0941\u092D\u093E\u0935\u0924\u0903 \u0938\u092A\u0926\u093F \u0935\u0947\u0926\u094D\u092F\u0924\u0947 \u0938\u093E \u092A\u0930\u093E \u0926\u0936\u093E \u0928\u0943\u092D\u093F\u0930\u0924\u0928\u094D\u0926\u094D\u0930\u093F\u0924\u093E\u0938\u092E\u0938\u0941\u0916\u093E\u092E\u0943\u0924\u0938\u094D\u092F\u0928\u094D\u0926\u093F\u0928\u0940\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u092E\u0939\u093E\u0917\u0941\u0930\u0941\u092D\u093F\u0930\u094D\u0928\u093F\u092C\u0926\u094D\u0927\u092E\u094D\u0965\u0968\u0967\u0965</p></div><hr><div class="trans"><p>Atrop\u0101yam\u0101ha\u2014</p><blockquote><p><strong>Magna\u1E25 svacittena pravi\u015Bet||21||</strong></p></blockquote><blockquote><p>Pr\u0101\u1E47\u0101disth\u016Blabh\u0101va\u1E41 tu tyaktv\u0101 s\u016Bk\u1E63mamath\u0101ntaram|<br> S\u016Bk\u1E63m\u0101t\u012Bta\u1E41 tu parama\u1E41 spandana\u1E41 labhyate yata\u1E25||</p></blockquote><p>ityupakramya</p><blockquote><p>... pravi\u015Bettatsvacetas\u0101||</p></blockquote><p>iti \u015Br\u012Bm\u1E5Btyujidbha\u1E6D\u1E6D\u0101rakanir\u016Bpitan\u012Bty\u0101 pr\u0101\u1E47\u0101y\u0101madhy\u0101nadh\u0101ra\u1E47\u0101disth\u016Blop\u0101y\u0101nparityajya svacitten\u0101vikalpakar\u016Bpe\u1E47\u0101ntarmukh\u0101ntaravimar\u015Bacamatk\u0101r\u0101tman\u0101 sa\u1E41vedanena pravi\u015Betsam\u0101vi\u015Bet| K\u012Bd\u1E5Bksan magna\u1E25 \u015Bar\u012Brapr\u0101\u1E47\u0101dipram\u0101t\u1E5Bt\u0101\u1E41 tatraiva ciccamatk\u0101rarase majjanena pra\u015Bamayan| Taduktam \u015Br\u012Bsvacchande</p><blockquote><p>Vy\u0101p\u0101ra\u1E41 m\u0101nasa\u1E41 tyaktv\u0101 bodhar\u016Bpe\u1E47a yojayet|<br> Tad\u0101 \u015Bivatvam\u0101y\u0101ti pa\u015Burmukto bhav\u0101r\u1E47av\u0101t||</p></blockquote><p>iti| \u015Ar\u012Bvij\xF1\u0101nabha\u1E6D\u1E6D\u0101rake&#39;pi</p><blockquote><p>M\u0101nasa\u1E41 cetan\u0101 \u015Baktir\u0101tm\u0101 ceti catu\u1E63\u1E6Dayam|<br> Yad\u0101 priye parik\u1E63\u012B\u1E47a\u1E41 tad\u0101 tadbhairava\u1E41 vapu\u1E25||</p></blockquote><p>iti| Etadeva j\xF1\u0101nagarbhe stotre</p><blockquote><p>Vih\u0101ya sakal\u0101\u1E25 kriy\u0101 janani m\u0101nas\u012B\u1E25 sarvato vimuktakara\u1E47akriy\u0101nus\u1E5Btip\u0101ratantryojjvalam|<br> Sthitaistvadanubh\u0101vata\u1E25 sapadi vedyate s\u0101 par\u0101 da\u015B\u0101 n\u1E5Bbhiratandrit\u0101samasukh\u0101m\u1E5Btasyandin\u012B||</p></blockquote><p>ityanena mah\u0101gurubhirnibaddham||21||</p></div><hr><p>\u041A\u0430\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0432 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 \u043F\u0440\u043E\u043F\u0438\u0442\u044B\u0432\u0430\u043D\u0438\u044F \u0442\u0440\u0435\u0445 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0422\u0443\u0440\u044C\u0435\u0439 (Turya)-- <em>(atra)</em>, [\u015Aiva] \u0443\u043F\u043E\u043C\u044F\u043D\u0443\u043B <em>(\u0101ha)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430 <em>(up\u0101yam)</em>\u2014</p><blockquote><p><strong>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0445\u043E\u0434\u0438\u0442\u044C \u0432 [\u044D\u0442\u043E \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0441\u043C. \u0430\u0444\u043E\u0440\u0438\u0437\u043C 20--] <em>(pravi\u015Bet)</em>, \u043F\u043E\u0433\u0440\u0443\u0436\u0430\u044F\u0441\u044C [\u0432 \u043D\u0435\u0433\u043E] <em>(magna\u1E25)</em> \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C <em>(sva)</em> \u0443\u043C\u043E\u043C <em>(cittena)</em>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0439, \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u043B\u0438\u0448\u0435\u043D \u0432\u0441\u044F\u043A\u043E\u0439 \u043C\u044B\u0441\u043B\u0438]||21||</strong></p></blockquote><p>[\u0412 M\u1E5Btyujit \u2014\u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0439 \u043A\u0430\u043A Netratantra\u2014 \u0431\u044B\u043B\u043E \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E,] \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>(upakramya)</em>:</p><blockquote><p>&quot;\u041E\u0441\u0442\u0430\u0432\u043B\u044F\u044F <em>(tu tyaktv\u0101)</em> \u0433\u0440\u0443\u0431\u043E\u0435 <em>(sth\u016Bla)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(bh\u0101vam)</em> \u043F\u0440\u0430\u043D\u044B <em>(pr\u0101\u1E47a)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u0438 \u0437\u0430\u0442\u0435\u043C <em>(atha)</em> [\u043E\u0442\u043A\u0430\u0437\u044B\u0432\u0430\u044F\u0441\u044C \u0434\u0430\u0436\u0435 \u043E\u0442] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(\u0101ntaram)</em> \u0442\u043E\u043D\u043A\u043E\u0439 <em>(s\u016Bk\u1E63mam)</em> [pr\u0101\u1E47\u0101y\u0101ma], \u0412\u044B\u0441\u0448\u0430\u044F <em>(paramam)</em> \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044F <em>(spandanam)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0430\u044F \u0432\u043D\u0435 <em>(\u0101t\u012Btam tu)</em> \u0442\u043E\u043D\u043A\u043E\u0439 [pr\u0101\u1E47\u0101y\u0101ma] <em>(s\u016Bk\u1E63ma)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F <em>(labhyate)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443 --\u0438\u0437-\u0437\u0430 \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 \u0433\u0440\u0443\u0431\u043E\u0439 \u0438 \u0442\u043E\u043D\u043A\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma-s-- <em>(yatas... iti)</em><sup>1</sup>&quot;||<br> [\u0421\u043C. VIII, 12 \u0432 Netratantra]</p></blockquote><p>[\u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u043D\u0430:]</p><blockquote><p>&quot;... \u043E\u043D \u0432\u0445\u043E\u0434\u0438\u0442 \u0432 <em>(pravi\u015Bet)</em> [\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C <em>(sva-cetas\u0101)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u043E\u043C\u0443 --\u0442.\u0435. \u043A\u0430\u043A \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439-- <em>(tad.. iti)</em><sup>2</sup>&quot;|<br> [\u0421\u043C. \u043F\u0435\u0440\u0432\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0441\u0442\u0440\u043E\u0444\u044B VIII, 14 \u0432 Netratantra]</p></blockquote><p>\u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u043C <em>(n\u012Bty\u0101)</em>, \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043D\u044B\u043C <em>(nir\u016Bpita)</em> \u0432 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C <em>(\u015Br\u012B... bha\u1E6D\u1E6D\u0101raka)</em> M\u1E5Btyujit --Netratantra-- <em>(m\u1E5Btyujit)</em>, \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 <em>(parityajya)</em> \u0433\u0440\u0443\u0431\u044B\u0445 <em>(sth\u016Bla)</em> \u043C\u0435\u0442\u043E\u0434\u043E\u0432 <em>(up\u0101y\u0101n)</em>, [\u0442\u0430\u043A\u0438\u0445 \u043A\u0430\u043A] pr\u0101\u1E47\u0101y\u0101ma <em>(pr\u0101\u1E47\u0101y\u0101ma)</em>, \u043C\u0435\u0434\u0438\u0442\u0430\u0446\u0438\u044F <em>(dhy\u0101na)</em>, \u043A\u043E\u043D\u0446\u0435\u043D\u0442\u0440\u0430\u0446\u0438\u044F <em>(dh\u0101ra\u1E47\u0101)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em>, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u0432\u043E\u0439\u0442\u0438 <em>(pravi\u015Bet)</em> [\u0438\u043B\u0438] \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u0443\u0442\u044C <em>(sam\u0101vi\u015Bet)</em> [\u0432 \u0422\u0443\u0440\u044C\u044E, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435] \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C <em>(svacittena)</em>, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sa\u1E41vedanena)</em>, \u043B\u0438\u0448\u0435\u043D\u043D\u044B\u043C \u043C\u044B\u0441\u043B\u0435\u0439 <em>(avikalpaka-r\u016Bpe\u1E47a)</em>, \u0438 \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(\u0101tman\u0101)</em> \u2014 \u0438\u043D\u0442\u0440\u043E\u0432\u0435\u0440\u0442\u043D\u0430\u044F <em>(antarmukha)</em> camatk\u0101ra --\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E, \u043F\u043E\u043B\u043D\u043E\u0435 \u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u044F-- <em>(bh\u016Btebhya\u1E25)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(\u0101ntara)</em> \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(vimar\u015Ba)</em> --\u0442.\u0435. \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F--|</p><p>\u041A\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(k\u012Bd\u1E5Bk san)</em>? \u041F\u043E\u0433\u0440\u0443\u0436\u0430\u044F\u0441\u044C [\u0432 \u044D\u0442\u043E] <em>(magna\u1E25)</em>, [\u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438,] \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u044F <em>(pra\u015Bamayan)</em> [\u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435], \u0447\u0442\u043E \u044D\u0442\u043E \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bra)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F <em>(pr\u0101\u1E47a)</em> \u0438 \u0442.\u0434. <em>(\u0101di)</em> \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F Pram\u0101t\u0101, \u0438\u043B\u0438 \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C --\u0432\u0430\u0448\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u042F, \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C-- <em>(pram\u0101t\u1E5Bt\u0101m)</em>, \u0447\u0435\u0440\u0435\u0437 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u0435 <em>(majjanena)</em> \u0432 \u044D\u0442\u043E \u0441\u0430\u043C\u043E\u0435 <em>(tatra eva)</em>, \u0442.\u0435 \u0432 \u044D\u043B\u0438\u043A\u0441\u0438\u0440 <em>(rase)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 <em>(camatk\u0101ra)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em> --\u043A\u043E\u0440\u043E\u0447\u0435, &quot;\u0432 \u0422\u0443\u0440\u044C\u044E (Turya), \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435&quot;--|</p><p>\u0422\u043E \u0436\u0435 <em>(tad)</em> \u0431\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;\u041E\u0442\u0431\u0440\u043E\u0441\u0438\u0432 <em>(tyaktv\u0101)</em> [\u0432\u0441\u044F\u043A\u0443\u044E] \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u0443\u044E <em>(m\u0101nasam)</em> \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C <em>(vy\u0101p\u0101ram)</em>, [Yog\u012B] \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u0442\u0430\u0442\u044C \u0435\u0434\u0438\u043D\u044B\u043C <em>(yojayet)</em> [\u0441 \u015Aiva] \u043F\u0440\u0438 [\u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0438] \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0431\u0435\u0437 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E \u043C\u044B\u0441\u043B\u0435\u0439 <em>(bodhar\u016Bpe\u1E47a)</em>. \u0422\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u0430\u044F \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C <em>(pa\u015Bu\u1E25)</em>, \u0431\u0443\u0434\u0443\u0447\u0438 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 <em>(mukta\u1E25)</em> \u043E\u0442 \u043E\u043A\u0435\u0430\u043D\u0430 <em>(ar\u1E47av\u0101t)</em> \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F --\u0442.\u0435. \u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u0439-- <em>(bhava)</em>, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(\u0101y\u0101ti)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u015Aiva <em>(\u015Bivatvam... iti)</em><sup>3</sup>&quot;||<br> [\u0421\u043C. IV, 437 \u0432 Svacchandatantra]</p></blockquote><p>[\u0418] \u0432 \u0441\u0430\u043C\u043E\u043C \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101na-bha\u1E6D\u1E6D\u0101rake)</em> [\u0431\u044B\u043B\u043E] \u0442\u0430\u043A\u0436\u0435 [\u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u0435] <em>(api)</em>:</p><blockquote><p>&quot;\u041E, \u0414\u043E\u0440\u043E\u0433\u0430\u044F <em>(priye)</em>!, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0433\u0440\u0443\u043F\u043F\u0430 \u0447\u0435\u0442\u044B\u0440\u0435\u0445 <em>(catu\u1E63\u1E6Dayam)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437] &#39;\u0443\u043C\u0430, \u043F\u043E\u043B\u043D\u043E\u0433\u043E \u0438\u0434\u0435\u0439 \u0438 \u0436\u0435\u043B\u0430\u043D\u0438\u0439 <em>(m\u0101nasam)</em>, \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(cetan\u0101)</em>, \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(\u015Bakti\u1E25)</em> \u0438 <em>(ca)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430 <em>(\u0101tm\u0101)</em>&#39; \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0430 <em>(parik\u1E63\u012B\u1E47am)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> [\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u044D\u0442\u0430 [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u0430\u044F] <em>(tad)</em> vapus, \u0438\u043B\u0438 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(vapus)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430\u044F \u043A\u0430\u043A] Bhairava --\u0413\u043E\u0441\u043F\u043E\u0434\u044C-- <em>(bhairavam... iti)</em>&quot;||</p></blockquote><p>\u042D\u0442\u0430 <em>(etad)</em> \u0436\u0435 \u0441\u0430\u043C\u0430\u044F [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(eva)</em> [\u0431\u044B\u043B\u0430 \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u0430] \u0432 \u0433\u0438\u043C\u043D\u0435 J\xF1\u0101nagarbha <em>(j\xF1\u0101nagarbhe stotre)</em> \u044D\u0442\u043E\u0439 [\u0441\u0442\u0440\u043E\u0444\u043E\u0439] <em>(anena)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0430 <em>(nibaddham)</em> \u0432\u0435\u043B\u0438\u043A\u0438\u043C \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u043C \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u043E\u043C <em>(mah\u0101-gurubhi\u1E25)</em> --\u044D\u0442\u043E \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A Pradyumnabha\u1E6D\u1E6Da, \u043E\u0434\u043D\u043E\u043C\u0443 \u0438\u0437 \u0433\u043B\u0430\u0432\u043D\u044B\u0445 \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432 Kalla\u1E6Da, \u0432\u044B\u0434\u0430\u044E\u0449\u0435\u043C\u0443\u0441\u044F \u0443\u0447\u0435\u043D\u0438\u043A\u0443 \u0441\u0430\u043C\u043E\u0433\u043E Vasugupta--:</p><blockquote><p>&quot;\u041E, \u041C\u0430\u0442\u044C <em>(janani)</em>!, \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043B\u043D\u043E\u0433\u043E <em>(sarvatas)</em> \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 <em>(vih\u0101ya)</em> \u0432\u0441\u044F\u043A\u043E\u0439 <em>(sakal\u0101\u1E25)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0439 <em>(m\u0101nas\u012B\u1E25)</em> \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 <em>(kriy\u0101\u1E25)</em>, [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435] \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(ujjvalam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u043E <em>(vimukta)</em> \u043E\u0442 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 <em>(p\u0101ratantrya)</em> \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F \u0437\u0430 <em>(anus\u1E5Bti)</em> \u0434\u0435\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E <em>(kriy\u0101)</em> \u043E\u0440\u0433\u0430\u043D\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em>. \u042D\u0442\u043E <em>(s\u0101)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(par\u0101)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(da\u015B\u0101)</em>, \u0438\u0441\u0442\u043E\u0447\u0430\u044E\u0449\u0435\u0435 <em>(syandin\u012B)</em> \u043D\u0435\u043A\u0442\u0430\u0440 <em>(am\u1E5Bta)</em> \u0431\u0435\u0441\u043F\u043E\u0434\u043E\u0431\u043D\u043E\u0433\u043E <em>(asama)</em> \u0441\u0447\u0430\u0441\u0442\u044C\u044F <em>(sukha)</em> \u0431\u0435\u0437 \u043A\u0430\u043A\u043E\u0433\u043E \u0431\u044B \u0442\u043E \u043D\u0438 \u0431\u044B\u043B\u043E \u043E\u0448\u0435\u043B\u043E\u043C\u043B\u0435\u043D\u0438\u044F \u0438\u043B\u0438 \u043D\u0435\u0434\u043E\u0443\u043C\u0435\u043D\u0438\u044F <em>(atandrita)</em>, \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0441\u044F <em>(vedyate)</em> \u043D\u0435\u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E <em>(sapadi)</em>, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0422\u0432\u043E\u0435\u0439 \u041C\u0438\u043B\u043E\u0441\u0442\u0438 <em>(tvat-anubh\u0101vata\u1E25)</em>, \u043B\u044E\u0434\u044C\u043C\u0438 <em>(n\u1E5Bbhi\u1E25)</em>, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C\u0438 [\u0432 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u043C \u0432\u0435\u043B\u0438\u043A\u043E\u043B\u0435\u043F\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438] <em>(sthitai\u1E25... iti)</em>&quot;||</p></blockquote><p>||21||</p><hr><ol><li>\u0427\u0442\u043E\u0431\u044B \u0432\u044B \u043F\u043E\u043D\u044F\u043B\u0438, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0441\u0442\u0440\u043E\u0444\u0443 \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043C\u043D\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u0432\u0430\u043C, \u043A\u0430\u043A K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u044D\u0442\u0443 \u0441\u0442\u0440\u043E\u0444\u0443 \u0432 \u0441\u0432\u043E\u0435\u0439 Netroddyota: &quot; \u092A\u094D\u0930\u093E\u0923\u093E\u0926\u094C \u092A\u094D\u0930\u093E\u0923\u093E\u092A\u093E\u0928\u0938\u092E\u093E\u0928\u0947\u0937\u0941 \u092F\u0903 \u0938\u094D\u0925\u0942\u0932\u094B \u0930\u0947\u091A\u0915\u092A\u0942\u0930\u0915\u093E\u0926\u093F\u0930\u094D\u092D\u093E\u0935\u0903 \u0938\u094D\u0935\u092D\u093E\u0935\u0938\u094D\u0924\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u0909\u091C\u094D\u091D\u093F\u0924\u094D\u0935\u093E \u0905\u0925\u0947\u0924\u093F \u090F\u0924\u0924\u094D\u0938\u094D\u0925\u0942\u0932\u092A\u094D\u0930\u093E\u0923\u093E\u092F\u093E\u092E\u093E\u0928\u0928\u094D\u0924\u0930\u092D\u093E\u0935\u093F \u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092E\u093E\u0928\u094D\u0924\u0930\u092E\u093F\u0924\u093F \u092E\u0927\u094D\u092F\u092A\u0925\u0947\u0928 \u0930\u0947\u091A\u0928\u093E\u091A\u092E\u0928\u093E\u0926\u093F\u0930\u0942\u092A\u0902 \u091A \u0924\u0902 \u0924\u094D\u092F\u0915\u094D\u0924\u094D\u0935\u093E \u092F\u0924\u094B \u092F\u0938\u094D\u092E\u093E\u0924\u094D\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u092E\u092A\u094D\u092F\u0924\u0940\u0924\u0902 \u092A\u0930\u092E\u092E\u093F\u0924\u093F \u092A\u094D\u0930\u093E\u0923\u093E\u0926\u094D\u092F\u091A\u093F\u0924\u094D\u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E \u0938\u094D\u092A\u0928\u094D\u0926\u0928\u0902 \u0932\u092D\u094D\u092F\u0924\u0947...&quot; - &quot;Pr\u0101\u1E47\u0101dau pr\u0101\u1E47\u0101p\u0101nasam\u0101ne\u1E63u ya\u1E25 sth\u016Blo recakap\u016Brak\u0101dirbh\u0101va\u1E25 svabh\u0101vasta\u1E41 tyaktv\u0101 ujjhitv\u0101 atheti etatsth\u016Blapr\u0101\u1E47\u0101y\u0101m\u0101nantarabh\u0101vi s\u016Bk\u1E63mam\u0101ntaramiti madhyapathena recan\u0101caman\u0101dir\u016Bpa\u1E41 ca ta\u1E41 tyaktv\u0101 yato yasm\u0101ts\u016Bk\u1E63mamapyat\u012Bta\u1E41 paramamiti pr\u0101\u1E47\u0101dyacitsphuratt\u0101tma spandana\u1E41 labhyate...&quot; - &quot;[\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435 &#39;Pr\u0101\u1E47\u0101disth\u016Blabh\u0101va\u1E41 tu tyaktv\u0101&#39; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435, \u0438\u043B\u0438 \u043E\u0442\u043A\u0430\u0437 \u043E\u0442 \u0433\u0440\u0443\u0431\u043E\u0433\u043E bh\u0101va \u2014\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u2014 \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u0432\u044B\u0434\u043E\u0445\u0430, \u0432\u0434\u043E\u0445\u0430 \u0438 \u0442.\u0434. \u0438 [\u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u0435\u043D\u043E] \u043D\u0430 pr\u0101\u1E47a, \u0438 \u0442.\u0434., \u0442.\u0435. \u043D\u0430 pr\u0101\u1E47a, ap\u0101na \u0438 sam\u0101na&#39;. [\u0424\u0440\u0430\u0437\u0430 &#39;s\u016Bk\u1E63mamath\u0101ntaram&#39; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u0438 \u0437\u0430\u0442\u0435\u043C \u043E\u0442\u043A\u0430\u0437\u0430\u0432\u0448\u0438\u0441\u044C \u043E\u0442 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0442\u043E\u043D\u043A\u043E\u0439 [pr\u0101\u1E47\u0101y\u0101ma], \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441\u0440\u0430\u0437\u0443 \u043F\u043E\u0441\u043B\u0435 \u0433\u0440\u0443\u0431\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma [\u0438] \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u044B\u0434\u043E\u0445, \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 \u0438 \u0442.\u0434. \u0447\u0435\u0440\u0435\u0437 \u0441\u0440\u0435\u0434\u0438\u043D\u043D\u044B\u0439 \u043F\u0443\u0442\u044C (\u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u044B\u0439 \u043A\u0430\u043D\u0430\u043B) --\u0442.\u0435. Su\u1E63umn\u0101--&#39;. &#39;Yatas&#39;, \u0442.\u0435. &#39;\u0438\u0437-\u0437\u0430 \u0447\u0435\u0433\u043E&#39; --\u0438\u0437-\u0437\u0430 \u043E\u0442\u043A\u0430\u0437\u0430 \u043E\u0442 \u0433\u0440\u0443\u0431\u043E\u0439 \u0438 \u0442\u043E\u043D\u043A\u043E\u0439 pr\u0101\u1E47\u0101y\u0101ma-s--, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0430\u044F \u0412\u0438\u0431\u0440\u0430\u0446\u0438\u044F [\u0438\u043B\u0438 Spanda], \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u0438\u0442 \u0434\u0430\u0436\u0435 \u0442\u043E\u043D\u043A\u0443\u044E pr\u0101\u1E47\u0101y\u0101ma --\u043F\u043E\u044D\u0442\u043E\u043C\u0443 \u0412\u044B\u0441\u0448\u0430\u044F-- \u0438 \u0447\u044C\u0435\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Sphuratt\u0101, \u0438\u043B\u0438 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u043D\u043E\u0435 \u043D\u0435\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u043E \u043F\u0435\u0440\u0435\u0434 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0435\u0439 --Pr\u0101\u1E47a--...&quot;.</li></ol><p>\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0421\u043F\u0430\u043D\u0434\u0430 \u2014 \u044D\u0442\u043E \u043D\u0438\u0447\u0442\u043E \u0438\u043D\u043E\u0435 \u043A\u0430\u043A \u0412\u044B\u0441\u0448\u0435\u0435 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u043F\u0440\u0435\u0434\u0448\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043B\u044E\u0431\u044B\u043C \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F\u043C, \u0442\u0430\u043A\u0438\u043C \u043A\u0430\u043A \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F \u0438 \u043F\u0440. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435. OK, \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u0441\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u044F\u0441\u043D\u043E... \u043A\u043E\u043D\u0435\u0447\u043D\u043E, \u0435\u0441\u043B\u0438 \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u043D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 pr\u0101\u1E47\u0101y\u0101ma, Su\u1E63umn\u0101, \u0438 \u0442.\u0434. \u0415\u0441\u043B\u0438 \u0432\u044B \u043D\u0435 \u0438\u043C\u0435\u0435\u0442\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043E\u0431 \u044D\u0442\u043E\u043C, \u0432\u0430\u043C \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0435\u0440\u0435\u0447\u0438\u0442\u0430\u0442\u044C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C \u044D\u0442\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F. \u041C\u043E\u0438 \u0438\u0437\u0432\u0438\u043D\u0435\u043D\u0438\u044F, \u043D\u043E \u044F \u043D\u0435 \u043C\u043E\u0433\u0443 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0442\u044C \u043E\u0434\u043D\u0438 \u0438 \u0442\u0435 \u0436\u0435 \u0432\u0435\u0449\u0438, \u0432\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0445\u0435-\u0445\u0435. \u0423\u0431\u0435\u0434\u0438\u0442\u0435\u0441\u044C, \u0447\u0442\u043E \u0432\u044B \u043E\u0447\u0435\u043D\u044C \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u044B \u0441 \u044D\u0442\u0438\u043C\u0438 \u043E\u0431\u0449\u0435\u043F\u0440\u0438\u043D\u044F\u0442\u044B\u043C\u0438 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u043C\u0438 \u0442\u0435\u0440\u043C\u0438\u043D\u0430\u043C\u0438, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u044B \u0431\u0443\u0434\u0435\u0442\u0435 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0441\u0442\u0430\u043B\u043A\u0438\u0432\u0430\u0442\u044C\u0441\u044F \u0441 \u043D\u0438\u043C\u0438 \u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0435 \u0438\u0437\u0443\u0447\u0435\u043D\u0438\u044F \u0422\u0440\u0438\u043A\u0438 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0441\u043A\u0438\u0445 \u0441\u0438\u0441\u0442\u0435\u043C.</p><ol start="2"><li>\u041A\u0430\u0436\u0435\u0442\u0441\u044F, \u0447\u0442\u043E K\u1E63emar\u0101ja \u0443\u043F\u0440\u043E\u0441\u0442\u0438\u043B \u044D\u0442\u0443 \u043C\u0430\u043B\u0435\u043D\u044C\u043A\u0443\u044E \u0447\u0430\u0441\u0442\u044C \u0438\u043B\u0438 \u0438\u043C\u0435\u043B \u0434\u0440\u0443\u0433\u043E\u0435 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0435. \u042F \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u043B \u0432 Netratantra VIII, 14: &quot; ... \u092A\u094D\u0930\u0935\u093F\u0936\u0947\u0926\u094D\u0927\u093E\u092E \u092A\u0930\u092E\u0902 \u0924\u0924\u094D\u0938\u094D\u0935\u091A\u0947\u0924\u0938\u093E\u0964&quot; - &quot;... pravi\u015Beddh\u0101ma parama\u1E41 tatsvacetas\u0101|&quot; - &quot;... \u043E\u043D \u0432\u0445\u043E\u0434\u0438\u0442 \u0432 \u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u0432\u043E\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u044D\u0442\u043E\u043C\u0443 --\u0442.\u0435. \u043A\u0430\u043A \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439--&quot;.</li></ol><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;pravi\u015Bet&quot; \u2014 \u044D\u0442\u043E \u0441\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0435 \u0433\u043B\u0430\u0433\u043E\u043B\u0430 &quot;pravi\u015B&quot; (\u0432\u0445\u043E\u0434\u0438\u0442\u044C) \u0432 \u041F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u043C \u041D\u0430\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0438, 3<sup>\u0435\u043C</sup> \u043B\u0438\u0446\u0435, \u0435\u0434. \u0447. (Parasmaipada), \u043E\u0431\u044B\u0447\u043D\u043E \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u043A\u0430\u043A &quot;\u0435\u043C\u0443/\u0435\u0439 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0445\u043E\u0434\u0438\u0442\u044C&quot;. \u041D\u043E \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0443, \u041F\u043E\u0442\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0435 \u041D\u0430\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 \u0438\u043C\u0435\u0435\u0442 \u0441\u0438\u043B\u0443 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E, &quot;pravi\u015Bet&quot; \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0442\u0430\u043A\u0436\u0435 \u0438\u043C\u0435\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434, \u043A\u0430\u043A &quot;\u043E\u043D/\u043E\u043D\u0430/\u043E\u043D\u043E \u0432\u0445\u043E\u0434\u0438\u0442&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043C\u043E\u0439 \u0432\u044B\u0448\u0435\u043F\u0440\u0438\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 &quot;pravi\u015Bet&quot; \u2014 \u0432 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438 (&quot;\u043E\u043D \u0432\u0445\u043E\u0434\u0438\u0442&quot;), \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0432 \u0441\u0430\u043C\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 21 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u044D\u0442\u043E \u043A\u0430\u043A &quot; \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u0445\u043E\u0434\u0438\u0442\u044C&quot;. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u044B \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0435, \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043F\u0435\u0440\u0435\u0432\u0435\u043B \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C.</p><ol start="3"><li>\u0421\u043D\u043E\u0432\u0430, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432 \u044D\u0442\u043E\u0439 \u0441\u0442\u0440\u043E\u0444\u0435 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0442\u0435\u0440\u043C\u0438\u043D\u0430 &quot;bodha&quot; \u043D\u0435\u044F\u0441\u043D\u043E, \u044F \u043E\u0431\u044A\u044F\u0441\u043D\u044E \u044D\u0442\u043E, \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0432 \u043A \u043F\u043E\u043C\u043E\u0449\u0438 Svacchandoddyota \u0432\u044B\u0434\u0430\u044E\u0449\u0435\u0433\u043E\u0441\u044F K\u1E63emar\u0101ja: &quot; \u092C\u094B\u0927\u0930\u0942\u092A\u0947\u0923\u0947\u0924\u093F \u0905\u0935\u093F\u0915\u0932\u094D\u092A\u0938\u0902\u0935\u093F\u0924\u094D\u0938\u094D\u092A\u0930\u094D\u0936\u0947\u0928\u0948\u0935&quot; - &quot;bodhar\u016Bpe\u1E47eti avikalpasa\u1E41vitspar\u015Benaiva&quot; - &quot;[\u0432\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] &#39;bodhar\u016Bpe\u1E47a&#39; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &#39;\u043F\u0440\u0438 \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u043E\u0432\u0435\u043D\u0438\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0431\u0435\u0437 \u043A\u0430\u043A\u0438\u0445-\u043B\u0438\u0431\u043E \u043C\u044B\u0441\u043B\u0435\u0439&#39;&quot;.</li></ol></div><div class="stanza"><a href="#s3.22" id="s3.22" class="num">3.22</a><div class="sans"><p>\u0907\u0924\u094D\u0925\u0902 \u091A \u092A\u0930\u092E\u092A\u0926\u092A\u094D\u0930\u0935\u093F\u0937\u094D\u091F\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u0935\u0938\u094D\u0924\u0941\u0938\u094D\u0935\u093E\u092D\u093E\u0935\u094D\u092F\u093E\u0926\u094D\u092F\u0926\u093E \u092A\u0941\u0928\u0903 \u092A\u094D\u0930\u0938\u0930\u0923\u0902 \u092D\u0935\u0924\u093F \u0924\u0926\u093E\u2014</p><blockquote><p><strong>\u092A\u094D\u0930\u093E\u0923\u0938\u092E\u093E\u091A\u093E\u0930\u0947 \u0938\u092E\u0926\u0930\u094D\u0936\u0928\u092E\u094D\u0965\u0968\u0968\u0965</strong></p></blockquote><p>\u092A\u0930\u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u0915\u0936\u093E\u0915\u094D\u0924\u092A\u0930\u093F\u092E\u0932\u0938\u0902\u0938\u094D\u0915\u0943\u0924\u0938\u094D\u092F \u092A\u094D\u0930\u093E\u0923\u0938\u094D\u092F \u0938\u092E\u094D\u092F\u0917\u093F\u0924\u093F \u0935\u093F\u0915\u0938\u093F\u0924\u0938\u092E\u0917\u094D\u0930\u0917\u094D\u0930\u0928\u094D\u0925\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0928\u094D\u0924\u0930\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092C\u0932\u093E\u0926\u094D \u0906 \u0908\u0937\u0926\u094D\u092C\u0939\u093F\u0930\u094D\u092E\u0928\u094D\u0926\u092E\u0928\u094D\u0926\u0902 \u091A\u093E\u0930\u0947 \u092A\u094D\u0930\u0938\u0930\u0923\u0947 \u0938\u092E\u0902 \u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u0918\u0928\u093E\u0924\u094D\u092E\u0924\u092F\u0948\u0915\u0930\u0942\u092A\u0902 \u0926\u0930\u094D\u0936\u0928\u0902 \u0938\u0902\u0935\u0947\u0926\u0928\u092E\u0930\u094D\u0925\u093E\u0924\u094D\u0938\u0930\u094D\u0935\u0926\u0936\u093E\u0938\u094D\u0935\u0938\u094D\u092F \u092D\u0935\u0924\u0940\u0924\u094D\u092F\u0930\u094D\u0925\u0903\u0964 \u0909\u0915\u094D\u0924\u0902 \u091A \u0936\u094D\u0930\u0940\u092E\u0926\u093E\u0928\u0928\u094D\u0926\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u0909\u0924\u094D\u0938\u0943\u091C\u094D\u092F \u0932\u094C\u0915\u093F\u0915\u093E\u091A\u093E\u0930\u092E\u0926\u094D\u0935\u0948\u0924\u0902 \u092E\u0941\u0915\u094D\u0924\u093F\u0926\u0902 \u0936\u094D\u0930\u092F\u0947\u0924\u094D\u0964<br> \u0938 \u0938\u092E\u0902 \u0938\u0930\u094D\u0935\u0926\u0947\u0935\u093E\u0928\u093E\u0902 \u0924\u0925\u093E \u0935\u0930\u094D\u0923\u093E\u0936\u094D\u0930\u092E\u093E\u0926\u093F\u0915\u0947\u0965<br> \u0926\u094D\u0930\u0935\u094D\u092F\u093E\u0923\u093E\u0902 \u0938\u092E\u0924\u093E\u0926\u0930\u094D\u0936\u0940 \u0938 \u092E\u0941\u0915\u094D\u0924\u0903 \u0938\u0930\u094D\u0935\u092C\u0928\u094D\u0927\u0928\u0948\u0903\u0964</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0905\u0924 \u090F\u0935 \u0936\u094D\u0930\u0940\u092A\u094D\u0930\u0924\u094D\u092F\u092D\u093F\u091C\u094D\u091E\u093E\u092F\u093E\u092E\u094D</p><blockquote><p>\u092C\u0941\u0926\u094D\u0927\u093F\u092A\u094D\u0930\u093E\u0923\u092A\u094D\u0930\u0938\u0930\u0947\u093D\u092A\u093F \u092C\u093E\u0939\u094D\u092F\u0926\u0947\u0936\u093E\u0926\u094D\u092F\u0941\u092A\u093E\u0926\u093E\u0928\u093E\u0928\u093E\u0939\u093F\u0924\u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0928\u093E\u0902 \u0935\u093F\u0936\u094D\u0935\u093E\u0924\u094D\u092E\u0938\u094D\u0935\u0930\u0942\u092A\u0932\u093E\u092D \u090F\u0935\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u094D\u0965\u0968\u0968\u0965</p></div><hr><div class="trans"><p>Ittha\u1E41 ca paramapadapravi\u1E63\u1E6Dasy\u0101sya vastusv\u0101bh\u0101vy\u0101dyad\u0101 puna\u1E25 prasara\u1E47a\u1E41 bhavati tad\u0101\u2014</p><blockquote><p><strong>Pr\u0101\u1E47asam\u0101c\u0101re samadar\u015Banam||22||</strong></p></blockquote><p>Parasphuratt\u0101tmaka\u015B\u0101ktaparimalasa\u1E41sk\u1E5Btasya pr\u0101\u1E47asya samyagiti vikasitasamagragranthy\u0101tmak\u0101ntar\u0101va\u1E63\u1E6Dambhabal\u0101d \u0101 \u012B\u1E63adbahirmandamanda\u1E41 c\u0101re prasara\u1E47e sama\u1E41 cid\u0101nandaghan\u0101tmatayaikar\u016Bpa\u1E41 dar\u015Bana\u1E41 sa\u1E41vedanamarth\u0101tsarvada\u015B\u0101svasya bhavat\u012Btyartha\u1E25| Ukta\u1E41 ca \u015Br\u012Bmad\u0101nandabhairave</p><blockquote><p>Uts\u1E5Bjya laukik\u0101c\u0101ramadvaita\u1E41 muktida\u1E41 \u015Brayet|<br> Sa sama\u1E41 sarvadev\u0101n\u0101\u1E41 tath\u0101 var\u1E47\u0101\u015Bram\u0101dike||<br> Dravy\u0101\u1E47\u0101\u1E41 samat\u0101dar\u015B\u012B sa mukta\u1E25 sarvabandhanai\u1E25|</p></blockquote><p>iti| Ata eva \u015Br\u012Bpratyabhij\xF1\u0101y\u0101m</p><blockquote><p>Buddhipr\u0101\u1E47aprasare&#39;pi b\u0101hyade\u015B\u0101dyup\u0101d\u0101n\u0101n\u0101hitasa\u1E45koc\u0101n\u0101\u1E41 vi\u015Bv\u0101tmasvar\u016Bpal\u0101bha eva||</p></blockquote><p>ityuktam||22||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham ca)</em>, \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0432\u043E\u0448\u0435\u043B \u0432 <em>(pravi\u1E63\u1E6Dasya)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(parama)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(pada)</em>, \u043A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 <em>(bhavati)</em> \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 --\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435-- <em>(prasara\u1E47am)</em> \u0441\u043D\u043E\u0432\u0430 <em>(punar)</em>, \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(sv\u0101bh\u0101vy\u0101t)</em> \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(vastu)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em>\u2014</p><blockquote><p><strong>\u041A\u043E\u0433\u0434\u0430 [\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442] \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E\u0435, \u043D\u043E \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0435 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435 <em>(sam\u0101c\u0101re)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 [Yog\u012B] <em>(pr\u0101\u1E47a)</em>, \u043D\u0430\u0441\u0442\u0443\u043F\u0430\u0435\u0442 \u0440\u0430\u0432\u043D\u043E\u0435 <em>(sama)</em> \u0432\u0438\u0434\u0435\u043D\u0438\u0435 <em>(dar\u015Banam)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C Yog\u012B \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E, \u043B\u0435\u0436\u0430\u0449\u0435\u0435 \u0432 \u043E\u0441\u043D\u043E\u0432\u0435 \u0432\u0441\u0435\u0433\u043E]||22||</strong></p></blockquote><p>&quot;\u0416\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 [Yog\u012B] <em>(pr\u0101\u1E47asya)</em>&quot; [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u0442\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0431\u044B\u043B\u0430 \u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0430 <em>(sa\u1E41sk\u1E5Btasya)</em> \u0430\u0440\u043E\u043C\u0430\u0442\u043E\u043C <em>(parimala)</em> \u015Aakti <em>(\u015B\u0101kta)</em>, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F <em>(\u0101tmaka)</em> \u0412\u044B\u0441\u0448\u0435\u0439 <em>(para)</em> Sphuratt\u0101, \u0438\u043B\u0438 \u0441\u0432\u0435\u0442\u044F\u0449\u0438\u043C\u0441\u044F \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(sphuratt\u0101)</em>&quot;. [\u0412 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435, \u0442\u0435\u0440\u043C\u0438\u043D &quot;sam\u0101c\u0101re&quot; \u2014 \u043C\u0435\u0441\u0442\u043D\u044B\u0439 (\u043B\u043E\u043A\u0430\u0442\u0438\u0432) \u043F\u0430\u0434\u0435\u0436 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0447\u0438\u0441\u043B\u0430 \u043E\u0442 &quot;sam\u0101c\u0101ra&quot;. \u041F\u0440\u0438\u0441\u0442\u0430\u0432\u043A\u0430 &quot;sam&quot; \u0432 &quot;sam\u0101c\u0101re&quot; \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442] &quot;samyak&quot; --\u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u044B\u0439 \u043E\u0442 &quot;samya\xF1c&quot;-- <em>(samyak iti)</em> [\u0438\u043B\u0438] &quot;\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0441\u0438\u043B\u044B <em>(bal\u0101t)</em> \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(ava\u1E63\u1E6Dambha)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 [\u0421\u0430\u043C\u043E\u0441\u0442\u0438] <em>(antara)</em>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0432\u0441\u0435 <em>(samagra)</em> \u0443\u0437\u043B\u044B <em>(granthi)</em> \u043E\u0442\u043A\u0440\u044B\u0442\u044B --\u0442.\u0435 \u0440\u0430\u0437\u0432\u044F\u0437\u0430\u043D\u044B-- <em>(vikasita)</em>&quot;<sup>1</sup>. [\u041F\u0440\u0438\u0441\u0442\u0430\u0432\u043A\u0430] &quot;\u0101&quot; [\u0432 &quot;sam\u0101c\u0101re&quot;] <em>(\u0101tmani)</em> [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430] &quot;\u043D\u0435\u0431\u043E\u043B\u044C\u0448\u0443\u044E <em>(\u012B\u1E63at)</em> \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u0443\u044E <em>(manda-mandam)</em> \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0432\u043E\u0432\u043D\u0435 <em>(bahis)</em>&quot;, [\u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A] &quot;c\u0101re&quot; [\u0432 &quot;sam\u0101c\u0101re&quot;] <em>(c\u0101re)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u0432 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0438 <em>(prasara\u1E47e)</em>&quot; --\u0442.\u0435. \u043A\u043E\u0433\u0434\u0430 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0438\u0435--. [\u0422\u0435\u0440\u043C\u0438\u043D] &quot;sama&quot; [\u0432 &quot;samadar\u015Banam&quot;] <em>(samam)</em> [\u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u043D\u0430] &quot;\u0442\u043E, \u0447\u0442\u043E \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E <em>(eka-r\u016Bpam)</em> \u043A\u0430\u043A <em>(\u0101tmatay\u0101)</em> \u043C\u0430\u0441\u0441\u0430 <em>(ghana)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0442.\u0435. \u015Aiva-- <em>(cit)</em> \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 --\u0442.\u0435. \u015Aakti-- <em>(\u0101nanda)</em>&quot;. [\u0412 \u0437\u0430\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435,] &quot;dar\u015Bana&quot; <em>(dar\u015Banam)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] &quot;\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C <em>(sa\u1E41vedanam)</em>&quot;. [\u0418\u0442\u0430\u043A,] \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0441\u043C\u044B\u0441\u043B\u0443 [\u0441\u043B\u043E\u0432] \u2014\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0431\u044B\u043B\u0438 \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u044B\u2014 <em>(arth\u0101t)</em>, [samadar\u015Bana, \u0438\u043B\u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0441\u0442\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0432\u0441\u0435 \u0435\u0434\u0438\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E \u043A\u0430\u043A \u043C\u0430\u0441\u0441\u0443 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430, \u0442.\u0435. &quot;\u0435\u0434\u0438\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043D\u043E\u0435 \u0432\u0438\u0434\u0435\u043D\u0438\u0435&quot;,] \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(bhavati)</em> \u0443 \u044D\u0442\u043E\u0433\u043E [Yog\u012B] <em>(asya)</em> \u043F\u0440\u0438 \u043B\u044E\u0431\u044B\u0445 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u0445 --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u0440\u0438 \u0432\u0441\u0435\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u044B \u0422\u0443\u0440\u044C\u0435\u0439, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C-- <em>(sarva-da\u015B\u0101su)</em>. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(iti artha\u1E25)</em>|</p><p>[\u042D\u0442\u043E \u0436\u0435] \u0442\u0430\u043A\u0436\u0435 \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam ca)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C \u0100nandabhairava <em>(\u015Br\u012Bmat-\u0101nandabhairave)</em>:</p><blockquote><p>&quot;\u041E\u0442\u043A\u0430\u0437\u0430\u0432\u0448\u0438\u0441\u044C \u043E\u0442 <em>(uts\u1E5Bjya)</em> \u043F\u0440\u0438\u0432\u044B\u0447\u043D\u044B\u0445 <em>(laukika)</em> \u043F\u0440\u0430\u043A\u0442\u0438\u043A <em>(\u0101c\u0101ram)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u0438\u0431\u0435\u0433\u043D\u0443\u0442\u044C <em>(\u015Brayet)</em> \u043A \u043D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(advaitam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0434\u0430\u0435\u0442 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 <em>(mukti-dam)</em>. \u041E\u043D <em>(sa\u1E25)</em> [\u0432\u0438\u0434\u0438\u0442] \u0440\u0430\u0432\u043D\u043E\u0441\u0442\u043D\u043E <em>(samam)</em> \u0432\u0441\u0435\u0445 \u0431\u043E\u0433\u043E\u0432 <em>(sarva-dev\u0101n\u0101m)</em>, \u0430 \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> \u043A\u0430\u0441\u0442\u044B <em>(var\u1E47a)</em>, \u044D\u0442\u0430\u043F\u044B \u0436\u0438\u0437\u043D\u0438 <em>(\u0101\u015Brama)</em>, \u0438 \u0442.\u043F. <em>(\u0101dike)</em><sup>2</sup>. \u041E\u043D \u043D\u0430\u0431\u043B\u044E\u0434\u0430\u0435\u0442 <em>(dar\u015B\u012B)</em> [\u0432\u0441\u0435] \u0432\u0435\u0449\u0438 <em>(dravy\u0101\u1E47\u0101m)</em> \u0441 \u043D\u0435\u0432\u043E\u0437\u043C\u0443\u0442\u0438\u043C\u043E\u0441\u0442\u044C\u044E <em>(samat\u0101)</em>. \u041E\u043D <em>(sa\u1E25)</em> \u0441\u0432\u043E\u0431\u043E\u0434\u0435\u043D <em>(mukta\u1E25)</em> \u043E\u0442 \u0432\u0441\u0435\u0445 \u043E\u043A\u043E\u0432 <em>(sarva-bandhanai\u1E25... iti)</em>&quot;||</p></blockquote><p>\u041F\u043E \u044D\u0442\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u0435 <em>(atas eva)</em>, \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E <em>(uktam)</em> \u0432 [\u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430] \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u0443\u044E \u012A\u015Bvarapratyabhij\xF1\u0101 <em>(\u015Br\u012B-pratyabhij\xF1\u0101y\u0101m)</em>:</p><blockquote><p>&quot;\u0414\u043B\u044F \u0442\u0435\u0445, \u0443 \u043A\u043E\u0433\u043E \u043D\u0435\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0439 <em>(an\u0101hita-sa\u1E45koc\u0101n\u0101m)</em>, [\u043F\u0440\u043E\u0438\u0437\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u0445] \u043F\u0440\u0435\u0434\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435\u043C <em>(up\u0101d\u0101na)</em> \u043E \u0432\u043D\u0435\u0448\u043D\u0435\u043C <em>(b\u0101hya)</em> \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 <em>(de\u015Ba)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, \u0434\u0430\u0436\u0435 \u0435\u0441\u043B\u0438 <em>(api)</em> \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 <em>(prasare)</em> \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0430 <em>(buddhi)</em> [\u0438] \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E\u0439 \u044D\u043D\u0435\u0440\u0433\u0438\u0438 <em>(pr\u0101\u1E47a)</em>, [\u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E] \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(l\u0101bha\u1E25 eva)</em> \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em> \u043A\u0430\u043A \u0421\u0430\u043C\u043E\u0441\u0442\u0438 <em>(\u0101tma)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva... iti)</em> --\u043A\u043E\u0440\u043E\u0447\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u043E\u043D\u0438 \u0432\u0438\u0434\u044F\u0442, \u0447\u0442\u043E \u0438\u0445 \u042F \u0435\u0441\u0442\u044C \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u0438\u043B\u0438 \u0414\u0443\u0448\u0430, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F--&quot;||</p></blockquote><p>||22||</p><hr><ol><li><p>\u0412 \u0442\u043E\u043D\u043A\u043E\u043C \u0442\u0435\u043B\u0435 \u0438\u043C\u0435\u0435\u0442\u0441\u044F \u0442\u0440\u0438 \u0443\u0437\u043B\u0430 (granthi-s), \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0445 Brahmagranthi, Vi\u1E63\u1E47ugranthi \u0438 Rudragranthi.\u041A\u0430\u0436\u0434\u044B\u0439 \u0438\u0437 \u044D\u0442\u0438\u0445 \u0443\u0437\u043B\u043E\u0432 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u043E\u0441\u043E\u0431\u043E\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435 (\u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0442\u0435\u043C\u0430!). \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F \u0421\u0430\u043C\u043E\u0441\u0442\u044C \u2014 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u0432\u043E\u0431\u043E\u0434\u043D\u0430, \u041E\u043D\u0430 \u043F\u043E\u044D\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442\u0441\u044F \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0435\u0439, \u043A\u0430\u043A \u0422\u0430, \u0443 \u043A\u043E\u0433\u043E \u0432\u0441\u0435 \u0443\u0437\u043B\u044B \u0440\u0430\u0437\u0432\u044F\u0437\u0430\u043D\u044B. \u0422\u0430\u043A\u043E\u0432\u043E \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435.</p></li><li><p>\u0421\u0438\u0441\u0442\u0435\u043C\u0430 \u043A\u0430\u0441\u0442 \u0438 \u044D\u0442\u0430\u043F\u043E\u0432 \u0436\u0438\u0437\u043D\u0438 \u2014 \u044D\u0442\u043E \u0434\u043B\u0438\u043D\u043D\u0430\u044F \u0438 \u0441\u043B\u043E\u0436\u043D\u0430\u044F \u0442\u0435\u043C\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0433\u043B\u0443\u0431\u043E\u043A\u043E \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u043E \u043C\u043D\u043E\u0433\u0438\u0445 \u041F\u0438\u0441\u0430\u043D\u0438\u044F\u0445 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0441\u0432\u043E\u0434 (\u0437\u0430\u043A\u043E\u043D\u043E\u0432) Manu). \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043F\u0440\u0438\u0432\u043E\u0436\u0443 \u0440\u0435\u0437\u044E\u043C\u0435:</p></li></ol><p>\u0418\u043C\u0435\u0435\u0442\u0441\u044F \u0447\u0435\u0442\u044B\u0440\u0435 \u043A\u0430\u0441\u0442\u044B, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, (1) Br\u0101hma\u1E47a \u2014\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0441\u043B\u0443\u0436\u0438\u0442\u0435\u043B\u0438\u2014, (2) K\u1E63atriya \u2014\u0447\u043B\u0435\u043D\u044B \u0432\u043E\u0435\u043D\u043D\u043E\u0433\u043E \u0438\u043B\u0438 \u0446\u0430\u0440\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0433\u043E \u0440\u043E\u0434\u0430\u2014, (3) Vai\u015Bya \u2014\u043B\u044E\u0434\u0438, \u0437\u0430\u043D\u044F\u0442\u044B\u0435 \u0442\u043E\u0440\u0433\u043E\u0432\u043B\u0435\u0439 \u0438 \u0441\u0435\u043B\u044C\u0441\u043A\u0438\u043C \u0445\u043E\u0437\u044F\u0439\u0441\u0442\u0432\u043E\u043C\u2014 \u0438 (4) \u015A\u016Bdra \u2014\u0441\u043B\u0443\u0433\u0438\u2014. \u0418 \u0438\u043C\u0435\u044E\u0442 \u043C\u0435\u0441\u0442\u043E \u0447\u0435\u0442\u044B\u0440\u0435 \u044D\u0442\u0430\u043F\u0430 \u0436\u0438\u0437\u043D\u0438, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, (1) Brahmac\u0101rin \u2014\u0443\u0447\u0435\u043D\u0438\u043A\u0438, \u0438\u0437\u0443\u0447\u0430\u044E\u0449\u0438\u0435 \u0412\u0435\u0434\u044B \u0438 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0435 \u0431\u0435\u0437\u0431\u0440\u0430\u0447\u0438\u044E, \u0434\u043E 25 \u043B\u0435\u0442\u2014, (2) G\u1E5Bhastha \u2014\u0434\u043E\u043C\u043E\u0432\u043B\u0430\u0434\u0435\u043B\u044C\u0446\u044B; \u0441 25 \u0434\u043E 50 \u043B\u0435\u0442\u2014, (3) V\u0101naprastha \u2014\u0437\u0430\u0442\u0432\u043E\u0440\u043D\u0438\u043A\u0438, \u043E\u0441\u0442\u0430\u0432\u0438\u0432\u0448\u0438\u0435 \u0441\u0432\u043E\u0438 \u0434\u043E\u043C\u0430 \u0438 \u0441\u0435\u043C\u044C\u0438 \u0434\u043B\u044F \u0430\u0441\u043A\u0435\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0436\u0438\u0437\u043D\u0438 \u0432 \u043B\u0435\u0441\u0443; \u0441 50 \u0434\u043E 75 \u043B\u0435\u0442\u2014 \u0438 (4) Sanny\u0101sin \u2014\u0442\u0435, \u043A\u0442\u043E \u043E\u0442\u0440\u0435\u043A\u0441\u044F \u043E\u0442 \u043C\u0438\u0440\u0441\u043A\u0438\u0445 \u0437\u0430\u0431\u043E\u0442, \u043E\u0442 75 \u043B\u0435\u0442\u2014.</p></div>',2),o=[p];function u(i,s,n,d,v,q){return e(),m("div",null,o)}var c=a(r,[["render",u]]);export{k as __pageData,c as default};
